+/// Abstract event loop interface
+pub const AbstractEventLoop = struct {
+    const Self = @This();
+
+    vtable: *const VTable,
+    _running: bool = false,
+    _closed: bool = false,
+
+    pub const VTable = struct {
+        run_forever: *const fn (*Self) void,
