+    /// Run one iteration of the event loop
+    pub fn run_once(self: *Self) void {
+        // Run ready callbacks
+        const ready = self._ready.items;
+        self._ready.clearRetainingCapacity();
+
+        for (ready) |handle| {
+            if (!handle._cancelled) {
+                handle._callback();
+            }
+        }
