+            .allocator = allocator,
+            ._proactor = proactor,
+            ._handle = handle,
+        };
+    }
+
+    pub fn is_closing(self: *const Self) bool {
+        return self._closing;
+    }
+
+    pub fn close(self: *Self) void {
+        self._closing = true;
+        self._closed = true;
+    }
+};
