+        _ = sizehint;
+        return self._buffer;
+    }
+
+    pub fn buffer_updated(self: *Self, nbytes: usize) void {
+        _ = nbytes;
+        _ = self;
+    }
+
+    pub fn eof_received(self: *Self) bool {
+        _ = self;
+        return false;
+    }
+
+    const default_vtable = BaseProtocol.VTable{
+        .connection_made = defaultConnectionMade,
