+/// A FIFO queue for asyncio
+pub fn Queue(comptime T: type) type {
+    return struct {
+        const Self = @This();
+
+        allocator: std.mem.Allocator,
+        _maxsize: usize,
+        _queue: std.ArrayList(T),
+        _getters: std.ArrayList(*Waiter),
