+fn testStaggeredRaceMultipleSuccess() !void {
+    const allocator = std.testing.allocator;
+    const coros = [_]*const fn () i32{ successCoro, successCoro2 };
+    const result = try staggered_race(allocator, i32, &coros, 0.25);
