+
+fn testMoveOnAfterCancelled() !void {
+    const allocator = std.testing.allocator;
+    var loop = test_events.EventLoop.init(allocator);
+    defer loop.deinit();
+
+    var t = move_on_after(&loop, 1.0);
+    _ = try t.enter();
+    t.exit(CancelledError);
