+/// Create a mock non-blocking socket (returns fd placeholder)
+pub fn mock_nonblocking_socket() !posix.socket_t {
+    const sock = try posix.socket(posix.AF.INET, posix.SOCK.STREAM | posix.SOCK.NONBLOCK, 0);
+    return sock;
+}
